+        let detect_time = ep.rejection_time.unwrap();
+        // With λ=0.9, p₀=1e-6: violation factor ≈ 1.9, need 1.9^n > 1/α = 1000.
+        // n = ceil(log(1000)/log(1.9)) = 11 violations → ~1100 observations.
