+        .prop_map(
+            |(txn_id, ordinal, tag, page_id, commit_pages, horizon_seq)| match tag {
+                0 => MvccAction::begin(txn_id, ordinal),
+                1 => MvccAction::read(txn_id, ordinal, page_id),
+                2 => MvccAction::write(txn_id, ordinal, page_id),
